import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is APR?", a: "APR, or annual percentage rate, estimates the yearly borrowing cost including interest and required loan fees." },
  { q: "What is the difference between APR and interest rate?", a: "The interest rate measures interest only. APR includes interest plus fees, so it is often higher." },
  { q: "How do you calculate APR?", a: "APR compares the loan payment and fees against the net amount received, then expresses that borrowing cost as an annual rate." },
  { q: "Why does APR matter when comparing loans?", a: "APR helps compare offers with different rates and fees using a single cost measure." },
  { q: "What is APY and how is it different from APR?", a: "APY measures earned yield with compounding, while APR measures borrowing cost and may not include compounding the same way." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, rate: number, months: number) { const r = rate / 100 / 12; return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months)); }
function aprFromPayment(net: number, monthly: number, months: number) {
  let low = 0, high = 1;
  for (let i = 0; i < 80; i++) { const mid = (low + high) / 2; const pv = monthly * (1 - Math.pow(1 + mid, -months)) / mid; if (pv > net) low = mid; else high = mid; }
  return (low + high) / 2 * 12 * 100;
}
function calc(amount: number, rate: number, months: number, fees: number) {
  const monthly = payment(amount, rate, months);
  const net = Math.max(1, amount - fees);
  return { monthly, apr: aprFromPayment(net, monthly, months), totalFees: fees, extra: monthly * months - amount + fees };
}

export default function APRCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(20000);
  const [rate, setRate] = useState(6);
  const [term, setTerm] = useState(60);
  const [origination, setOrigination] = useState(2);
  const [broker, setBroker] = useState(250);
  const [other, setOther] = useState(100);
  const fees = amount * origination / 100 + broker + other;
  const result = useMemo(() => calc(amount, rate, term, fees), [amount, rate, term, fees]);
  const feeRates = [0, 0.5, 1, 2, 3];
  const noFee = calc(20000, 6, 60, 0);
  return (
    <>
      <SEOHead title="Free APR Calculator Online - Calculate True Annual Percentage Rate Instantly | CalcHive" description="Free online APR calculator. Calculate the true APR including all fees for any loan to compare the real cost of borrowing from any lender instantly. 100% free, no signup required." canonical="/apr-calculator" keywords="free APR calculator, annual percentage rate calculator free online, calculate APR free, APR vs interest rate calculator free, true cost of loan calculator free" category="Financial Calculators" breadcrumbName="Free APR Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free APR Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate true annual percentage rate including origination, broker, and other loan fees.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term months</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Origination fee (%)</label><input type="number" value={origination} onChange={(e) => setOrigination(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Broker fee</label><input type="number" value={broker} onChange={(e) => setBroker(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Other costs</label><input type="number" value={other} onChange={(e) => setOther(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">True APR</p><p className="text-5xl sm:text-6xl font-black text-white">{pct(result.apr)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly payment</p><p className="text-lg font-extrabold text-foreground">{money(result.monthly)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total fees</p><p className="text-lg font-extrabold text-foreground">{money(result.totalFees)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Interest + fees</p><p className="text-lg font-extrabold text-foreground">{money(result.extra)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate True APR Including All Fees for Free</h2><p className="text-muted-foreground leading-relaxed">APR accounts for the loan payment and required fees so loans with different fee structures can be compared more fairly.</p><h2 className="text-2xl font-bold text-foreground">APR vs Interest Rate - What Is the Difference</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">How Fees Affect APR on a $20,000 Loan at 6% Interest</caption><thead className="bg-muted/60"><tr>{["Origination Fee", "Effective APR", "Monthly Payment", "Total Fees Paid", "Extra Cost vs No Fee"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{feeRates.map((f) => { const row = calc(20000, 6, 60, 20000 * f / 100); return <tr key={f}><td className="py-2.5 px-3 font-semibold">{f}%</td><td className="py-2.5 px-3">{pct(row.apr)}</td><td className="py-2.5 px-3">{money(row.monthly)}</td><td className="py-2.5 px-3">{money(row.totalFees)}</td><td className="py-2.5 px-3">{money(row.extra - noFee.extra)}</td></tr>; })}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Annual Percentage Rate Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use APR when comparing loan offers because a low interest rate can still be expensive if fees are high.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/apr-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


